namespace QBEngineer.Api.Capabilities;

/// <summary>
/// Phase 4 Phase-A — Authoritative static catalog of every capability the
/// application knows about. Mirrors the Phase 4A capability catalog markdown
/// (e:/dev/qb-engineer/phase-4-output/4A-capability-catalog/capability-catalog.md).
/// 
/// 128 rows from the catalog body + 1 (CAP-IDEN-CAPABILITY-ADMIN) per 4E-
/// decisions-log #9 / 4F-decisions-log #1 = 129 total. The catalog header
/// claims 121 because three INV/QC/MD entries are listed in two areas; the
/// Phase A implementation treats every distinct code as one row and accepts
/// the count-discrepancy. See _catalog-rows.cs.txt and the 4F implementation-
/// decisions doc for the parse / count discussion.
/// 
/// The seeder (<see cref="Seeding.CapabilityCatalogSeeder"/>) upserts these
/// into the <c>capabilities</c> table on startup. Per 4F decision #4 the
/// upsert is INSERT-on-missing only — never overwrites the
/// <see cref="Core.Entities.Capability.Enabled"/> column once it exists.
/// </summary>
public static class CapabilityCatalog
{
    public static IReadOnlyList<CapabilityDefinition> All { get; } = new List<CapabilityDefinition>
    {
        new("CAP-IDEN-AUTH-PASSWORD", "IDEN", @"Password authentication", @"Username/password sign-in with self-service reset and account lockout after failed attempts. The base authentication capability — every other identity feature layers on top. Disabling this would leave only kiosk-tier auth, which is not a serious deployment.", IsDefaultOn: true, RequiresRoles: null),
        new("CAP-IDEN-AUTH-MFA", "IDEN", @"Multi-factor authentication (TOTP)", @"TOTP-based second factor with recovery codes. Required by some regulated industries and good practice for any admin account.", IsDefaultOn: false, RequiresRoles: null),
        new("CAP-IDEN-AUTH-SSO", "IDEN", @"Single sign-on (Google / Microsoft / OIDC)", @"OAuth/OIDC sign-in delegation to an external identity provider. Mid-market and enterprise companies usually require SSO; small shops typically don't.", IsDefaultOn: false, RequiresRoles: null),
        new("CAP-IDEN-AUTH-API-KEYS", "IDEN", @"BI / integration API keys", @"Long-lived API keys distinct from user JWT tokens, scoped for read-only data export to BI tools. Required for companies that pipe ERP data into PowerBI / Tableau / Looker.", IsDefaultOn: false, RequiresRoles: null),
        new("CAP-IDEN-AUTH-KIOSK", "IDEN", @"Kiosk / RFID / NFC / barcode auth tier", @"Tiered kiosk authentication: a shared shop-floor terminal authenticates via badge scan + PIN rather than full password. Required for shops where production workers don't have email / web logins.", IsDefaultOn: false, RequiresRoles: null),
        new("CAP-IDEN-USERS", "IDEN", @"System user management", @"CRUD for system user accounts (login-bearing principals), distinct from employees. Per WU-19 employee/user split: a user is an optional grant on top of an employee, or a non-employee principal (consultant, service account).", IsDefaultOn: true, RequiresRoles: null),
        new("CAP-IDEN-ROLES", "IDEN", @"Role-based access control", @"Named role assignment to users (Administrator, Controller, Sales, Production Manager, Floor Operator, etc.). Permissions are role-additive. The roles list itself is configurable; templates are seeded.", IsDefaultOn: true, RequiresRoles: null),
        new("CAP-IDEN-TENANT-CONFIG", "IDEN", @"Company / tenant configuration", @"Single-tenant identity: company name, address, locale, time zone, fiscal year start, primary currency, costing model. Configured once at install; rarely changed afterward. Single-tenant per database (no multi-tenancy).", IsDefaultOn: true, RequiresRoles: null),
        new("CAP-IDEN-AUDIT-SYSTEM-LOG", "IDEN", @"System-wide audit log", @"Cross-entity event log for compliance and security review: logins, role changes, MFA events, period close, system configuration changes, deactivation sweeps, bulk role assignment. Distinct from per-entity activity logs; immutable.", IsDefaultOn: true, RequiresRoles: null),
        new("CAP-MD-CUSTOMERS", "MD", @"Customer master", @"Customer records (B2B accounts) with contacts, addresses, payment terms, credit limits, and per-customer pricing eligibility. The anchor of the order-to-cash flow.", IsDefaultOn: true, RequiresRoles: null),
        new("CAP-MD-VENDORS", "MD", @"Vendor master", @"Vendor / supplier records with addresses, terms, tax-form tracking, scorecards. The anchor of procure-to-pay.", IsDefaultOn: true, RequiresRoles: null),
        new("CAP-MD-PARTS", "MD", @"Part / item master", @"Part records covering raw, WIP, and finished goods, with attributes for type, UoM, default cost, lead time, lot/serial flags, hazmat flag, ABC class. The anchor of all material flows.", IsDefaultOn: true, RequiresRoles: null),
        new("CAP-MD-BOM", "MD", @"Bill of materials", @"Component lists for produced items, with quantity-per, UoM, alternates, and revision history. References parts. Required for any company that produces multi-component goods.", IsDefaultOn: true, RequiresRoles: null),
        new("CAP-MD-ROUTING", "MD", @"Operation routings", @"Sequence of operations through work centers needed to produce a part, with run/setup time, scrap factor, subcontract metadata. References parts and work centers.", IsDefaultOn: true, RequiresRoles: null),
        new("CAP-MD-WORKCENTERS", "MD", @"Work centers", @"Production-capable work centers within a location: capacity, calendar override, labor rate, qualifications. Operations route through them.", IsDefaultOn: true, RequiresRoles: null),
        new("CAP-MD-LOCATIONS", "MD", @"Locations / plants", @"Physical sites where the business operates (plants, warehouses, offices). Most records are scoped to a location. Multi-plant requires this enabled.", IsDefaultOn: true, RequiresRoles: null),
        new("CAP-MD-CALENDARS", "MD", @"Calendars (shifts, holidays, downtime)", @"Plant and per-work-center calendars defining when work happens: shift times, weekends, holidays, planned downtime. Capacity calculations depend on this.", IsDefaultOn: true, RequiresRoles: null),
        new("CAP-MD-EMPLOYEES", "MD", @"Employee master", @"People employed by the business with hire date, location, pay info. Distinct from system users (an employee may or may not have a user account).", IsDefaultOn: true, RequiresRoles: null),
        new("CAP-MD-ASSETS", "MD", @"Fixed asset master", @"Equipment, tooling, vehicles owned and used (not consumed) by the business. Tracks acquisition cost, useful life, location, custodian. Anchors PM scheduling and (when accounting full-GL is enabled) depreciation.", IsDefaultOn: true, RequiresRoles: null),
        new("CAP-MD-PRICELIST", "MD", @"Customer price lists", @"Per-customer-tier or per-customer pricing tables. Required when a shop has tiered pricing (volume discounts, contract pricing) rather than flat list price.", IsDefaultOn: false, RequiresRoles: null),
        new("CAP-MD-UOM", "MD", @"Units of measure", @"Unit definitions (each, kg, lb, hour, foot, gallon) and conversion factors between them. Every part needs a primary UoM; some parts need multi-UoM (e.g., coil tracked in feet, consumed in pounds).", IsDefaultOn: true, RequiresRoles: null),
        new("CAP-MD-CURRENCIES", "MD", @"Currencies and exchange rates", @"Currency definitions and exchange-rate tables. Required for shops that buy from foreign vendors or sell to foreign customers. Single-currency shops can leave at default.", IsDefaultOn: true, RequiresRoles: null),
        new("CAP-MD-TAXCODES", "MD", @"Sales tax codes / VAT codes", @"Tax classifications applied to transactions. US sales tax by state, EU VAT, exempt codes. Required for any shop selling taxable goods.", IsDefaultOn: true, RequiresRoles: null),
        new("CAP-MD-CONTRACTS-CONSIGNMENT", "MD", @"Consignment / customer-managed contracts", @"Long-running supply agreements: consignment inventory, blanket orders, vendor-managed inventory. Distinct from standard PO/SO transactions.", IsDefaultOn: false, RequiresRoles: null),
        new("CAP-MD-ECO", "MD", @"Engineering change orders", @"Formal change-control workflow for BOMs, routings, and part attributes. Required by regulated industries (aerospace, medical, automotive) where every change needs review-approve-implement traceability.", IsDefaultOn: false, RequiresRoles: null),
