        new("CAP-O2C-RECURRING", "O2C", @"Recurring / subscription orders", @"Repeating order schedules: weekly/monthly/quarterly auto-generation. Used by service contracts and subscription consumables.", IsDefaultOn: false, RequiresRoles: null),
        new("CAP-O2C-PICKPACK", "O2C", @"Pick / pack", @"Warehouse pick wave generation, pick confirmation, packing into shipment packages with weights/dimensions. Splits from ship to allow companies that don't formalize picking (small shops) to skip.", IsDefaultOn: true, RequiresRoles: null),
